import { NextResponse } from 'next/server';
import { GoogleGenAI } from '@google/genai';

const ai = new GoogleGenAI({ apiKey: process.env.GEMINI_API_KEY });

export async function POST(req) {
  try {
    const body = await req.json();
    const { person_image, garment_image } = body;

    if (!person_image || !garment_image) {
      return NextResponse.json({ error: "Both person and garment images are required." }, { status: 400 });
    }

    const personBase64 = person_image.replace(/^data:image\/\w+;base64,/, '');
    const garmentBase64 = garment_image.replace(/^data:image\/\w+;base64,/, '');

    console.log("Calling Gemini 2.0 Flash for Prompt Generation...");
    
    // 1. Generate Prompt using Gemini
    const promptResponse = await ai.models.generateContent({
      model: "gemini-2.0-flash",
      contents: [
        {
          role: "user",
          parts: [
            { inlineData: { data: personBase64, mimeType: "image/jpeg" } },
            { inlineData: { data: garmentBase64, mimeType: "image/jpeg" } },
            { text: "Analyze the first image (a person) and the second image (a garment). Write a single, highly detailed image generation prompt (in English) describing a realistic, high-quality, full-body photograph of THIS EXACT person wearing THIS EXACT garment. Return ONLY the prompt text, nothing else." }
          ]
        }
      ]
    });
    
    const imagenPrompt = promptResponse.text.trim();
    console.log("Generated prompt for Image Gen:", imagenPrompt);

    // 2. Generate Image using Pollinations AI (Free, no API key needed, no 404s)
    console.log("Fetching image from pollinations.ai...");
    const pollinationsUrl = `https://image.pollinations.ai/prompt/${encodeURIComponent(imagenPrompt)}?width=768&height=1024&nologo=true&enhance=true`;
    
    // Fetch the image as a buffer
    const imgRes = await fetch(pollinationsUrl);
    if (!imgRes.ok) throw new Error("Image download failed from generation service.");
    
    const arrayBuffer = await imgRes.arrayBuffer();
    const buffer = Buffer.from(arrayBuffer);
    const generatedBase64 = buffer.toString('base64');
    
    return NextResponse.json({
      result_image: `data:image/jpeg;base64,${generatedBase64}`
    });

  } catch (error) {
    console.error("Pipeline Error:", error);
    return NextResponse.json({ 
      error: error.message || "Failed to generate image." 
    }, { status: 500 });
  }
}
